#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "createClient")]
pub fn create_client(
    api_key: String,
    base_url: Option<String>,
    timeout_secs: Option<i64>,
    max_retries: Option<u32>,
    model_hint: Option<String>,
) -> Result<JsDefaultClient> {
    liter_llm::bindings::create_client(
        api_key,
        base_url,
        timeout_secs.map(|v| v as u64),
        max_retries.map(|v| v),
        model_hint,
    )
    .map(|val| JsDefaultClient { inner: Arc::new(val) })
    .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "createClientFromJson")]
pub fn create_client_from_json(json: String) -> Result<JsDefaultClient> {
    liter_llm::bindings::create_client_from_json(&json)
        .map(|val| JsDefaultClient { inner: Arc::new(val) })
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "registerCustomProvider")]
pub fn register_custom_provider(config: JsCustomProviderConfig) -> Result<()> {
    let config_core: liter_llm::CustomProviderConfig = config.into();
    liter_llm::provider::custom::register_custom_provider(config_core)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "unregisterCustomProvider")]
pub fn unregister_custom_provider(name: String) -> Result<bool> {
    liter_llm::provider::custom::unregister_custom_provider(&name)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

